#!/usr/bin/env node
/**
 * review-checklist-advisory.js — SessionStart hook (D3).
 *
 * When a `.claude/brain-review-checklist.md` exists in the project, injects a
 * single one-line advisory so the agent (and the native `/code-review`) knows to
 * read it as review context. Cooldown-guarded; silent when the file is absent.
 *
 * The checklist itself is (re)generated by the promotion scan (brain-promote.js),
 * so this hook only points at it — no KB access here.
 */
'use strict';

const fs = require('fs');
const path = require('path');
const os = require('os');

const { readStdin, parsePayload, emitEmpty, emitJson } = require('./lib/hook-io.js');
const { CHECKLIST_RELPATH } = require('./lib/review-checklist.js');

const COOLDOWN_MS = 6 * 60 * 60 * 1000; // at most once per 6h per project

function dataDir() {
  const env = process.env.CLAUDE_PLUGIN_DATA;
  return (env && !env.includes('${'))
    ? env : path.join(os.homedir(), '.claude', 'plugins', 'data', 'claude-code-boss');
}

function stampPath(cwd) {
  const key = Buffer.from(String(cwd || '')).toString('base64').replace(/[/+=]/g, '').slice(-32);
  return path.join(dataDir(), '.runtime', `review-checklist-advisory-${key}.json`);
}

function onCooldown(p) {
  try {
    const last = JSON.parse(fs.readFileSync(p, 'utf8')).ts;
    return Number.isFinite(last) && (Date.now() - last) < COOLDOWN_MS;
  } catch { /* absent → not on cooldown */ return false; }
}

function stamp(p) {
  try { fs.mkdirSync(path.dirname(p), { recursive: true }); fs.writeFileSync(p, JSON.stringify({ ts: Date.now() })); }
  catch (e) { void e; }
}

/** Count unchecked items ("- [ ]") for a more useful one-liner. Best-effort. */
function countItems(md) {
  const m = String(md || '').match(/^- \[ \]/gm);
  return m ? m.length : 0;
}

async function main() {
  const raw = await readStdin();
  const event = parsePayload(raw) || {};
  const eventName = event.hook_event_name || 'SessionStart';
  const cwd = event.cwd || process.cwd();

  const checklist = path.join(cwd, ...CHECKLIST_RELPATH);
  let md;
  try { md = fs.readFileSync(checklist, 'utf8'); }
  catch { /* no checklist → nothing to advise */ return emitEmpty(); }

  const sp = stampPath(cwd);
  if (onCooldown(sp)) return emitEmpty();
  stamp(sp);

  const n = countItems(md);
  const rel = CHECKLIST_RELPATH.join('/');
  emitJson({
    hookSpecificOutput: {
      hookEventName: eventName,
      additionalContext: `[REVIEW] This project has a Brain review checklist (${rel}, ${n} recurring lesson${n === 1 ? '' : 's'}). `
        + `Read it before code review — check changes against these recurring mistakes; \`/code-review\` should use it as context.`,
    },
  });
}

if (require.main === module) {
  main().catch((err) => { console.error(`[review-checklist-advisory] ${err.message}`); emitEmpty(); });
}

module.exports = { onCooldown, stampPath, countItems, COOLDOWN_MS };
